# ---------------------------------------------------------------------------
# Logging filter — suppress noisy static-file 304s from uvicorn access log
# ---------------------------------------------------------------------------

import logging

class _SuppressStaticAccessLog(logging.Filter):
    def filter(self, record: logging.LogRecord) -> bool:
        msg = record.getMessage()
        if "GET /static/" in msg or "GET /favicon.ico" in msg:
            return False
        return True

logging.getLogger("uvicorn.access").addFilter(_SuppressStaticAccessLog())

