class _BackendHolder:
    """Mutable holder to break the circular dependency between
    TelegramUserBridge.backend_handler and BackendService.
    """
    def __init__(self, backend: BackendService) -> None:
        self.backend: BackendService = backend


def _bootstrap() -> tuple[ChatService, BackendService, WebChatStore, TelegramUserChatStore | None, TelegramUserBridge | None] | None:
    try:
        config, _ = AppConfig.load(mode="standard")
        _blog.init(config.logs_dir)
        _blog.log("events", "Bootstrap started")
        chat_service = ChatService.from_config(config)
        chat_service.runtime_state_store = FileSystemRuntimeStateStore(chat_service.storage)
        backend_holder = _BackendHolder(BackendService(chat_service))
        web_chat_dir = config.standard_dir / "web_chats"
        builder = getattr(chat_service, "session_index_builder", None)
        chat_store = WebChatStore(
            web_chat_dir,
            index_callback=lambda p: builder.index_web_chat(p) if builder else None,
        )
        if builder is not None:
            try:
                builder.rebuild_web_chats(web_chat_dir / "chats")
            except Exception as exc:
                pass
        obs_builder = getattr(chat_service, "obsidian_index_builder", None)
        if obs_builder is not None and chat_service.config.obsidian_vault_enabled:
            try:
                obs_builder.rebuild(chat_service.config.obsidian_vault_path)
            except Exception as exc:
                pass
        tg_user_chat_dir = config.standard_dir / "telegram_user_chats"
        tg_chat_store = TelegramUserChatStore(tg_user_chat_dir)
        tg_rate_limiter = TelegramUserRateLimiter(
            interval_sec=config.telegram_user_rate_limit_interval_sec,
            burst_count=config.telegram_user_rate_limit_burst_count,
            window_min=config.telegram_user_rate_limit_window_min,
        )
        tg_monitor = ConnectionMonitor()
        tg_bridge = TelegramUserBridge(
            config=chat_service.config,
            backend_handler=lambda source, chat_id, text, metadata=None: backend_holder.backend.handle(
                BackendRequest(kind="message", text=text, chat_id=str(chat_id), client="web", source=source, metadata=metadata or {})
            ),
            chat_store=tg_chat_store,
            rate_limiter=tg_rate_limiter,
            connection_monitor=tg_monitor,
        )
        backend_holder.backend = BackendService(
            chat_service=chat_service,
            telegram_user_chat_store=tg_chat_store,
            telegram_user_bridge=tg_bridge,
        )
        backend = backend_holder.backend
        _blog.log("events", "Bootstrap completed")
        return chat_service, backend, chat_store, tg_chat_store, tg_bridge
    except (ConfigError, StorageError, LLMClientError) as exc:
        _blog.log("events", f"Bootstrap failed: {exc}")
        print(f"Web runtime bootstrap failed: {exc}")
        return None


tg_user_chat_store: TelegramUserChatStore | None = None
tg_user_bridge: TelegramUserBridge | None = None
git_backup_service: Any | None = None
_status_notes_cache: tuple[int, float] | None = None

_bootstrap_result = _bootstrap()
if _bootstrap_result is None:
    chat_service: ChatService | None = None
    backend: BackendService | None = None
    chat_store: WebChatStore | None = None
    tg_user_chat_store = None
    tg_user_bridge = None
else:
    chat_service, backend, chat_store, tg_user_chat_store, tg_user_bridge = _bootstrap_result

# Per-chat concurrency locks
_locks: dict[str, asyncio.Lock] = {}
_locks_lock = asyncio.Lock()


async def _get_chat_lock(chat_id: str) -> asyncio.Lock:
    async with _locks_lock:
        if chat_id not in _locks:
            _locks[chat_id] = asyncio.Lock()
        return _locks[chat_id]


_reload_lock = asyncio.Lock()


def _is_uvicorn_reload() -> bool:
    """True if this process is a uvicorn worker running under --reload."""
    # On Windows uvicorn uses multiprocessing.spawn for reload.
    # The supervisor passes --reload in sys.argv which is inherited by the child.
    return "--reload" in sys.argv and multiprocessing.parent_process() is not None


async def _do_cleanup(close_blog: bool = True) -> None:
    """Gracefully stop all background services and flush logs."""
    global tg_user_bridge
    if tg_user_bridge is not None:
        try:
            tg_user_bridge.stop()
        except Exception:
            pass
        tg_user_bridge = None

    if chat_service is not None:
        for attr in ("activity_collector", "clipboard_service", "fs_watcher", "sleep_mode_service", "session_index_watcher"):
            svc = getattr(chat_service, attr, None)
            if svc is not None and hasattr(svc, "stop"):
                try:
                    svc.stop()
                except Exception:
                    pass

    _blog.flush()
    if close_blog:
        _blog.close()


async def _do_reload() -> None:
    global chat_service, backend, chat_store, tg_user_chat_store, tg_user_bridge, git_backup_service
    async with _reload_lock:
        print("[reload] triggered")
        _blog.log("events", "Reload triggered")
        _blog.flush()

        await _do_cleanup(close_blog=False)

        if _is_uvicorn_reload():
            print("[reload] respawning process (uvicorn --reload detected)")
            _blog.log("events", "Reload respawning process")
            _blog.flush()
            await asyncio.sleep(0.2)
            sys.exit(3)

        if git_backup_service is not None:
            try:
                git_backup_service.stop()
            except Exception:
                pass
            git_backup_service = None

        old_blog = _blog.get_default()
        result = _bootstrap()
        if result is None:
            print("[reload] bootstrap failed — keeping previous state")
            # Close whichever logger is active; then close old_blog if it differs.
            try:
                _blog.close()
            except Exception:
                pass
            if old_blog is not None and old_blog is not _blog.get_default():
                try:
                    old_blog.close()
                except Exception:
                    pass
            return

        chat_service, backend, chat_store, tg_user_chat_store, tg_user_bridge = result
        # Start session index watcher after reload (async context has running loop)
        watcher = getattr(chat_service, "session_index_watcher", None)
        if watcher is not None and hasattr(watcher, "start"):
            watcher.start()
        # Rebuild web-chat index after reload
        builder = getattr(chat_service, "session_index_builder", None)
        if builder is not None:
            try:
                builder.rebuild_web_chats(chat_service.config.standard_dir / "web_chats" / "chats")
            except Exception as exc:
                print(f"[reload] rebuild_web_chats warning: {exc}")
        obs_builder = getattr(chat_service, "obsidian_index_builder", None)
        if obs_builder is not None and chat_service.config.obsidian_vault_enabled:
            try:
                obs_builder.rebuild(chat_service.config.obsidian_vault_path)
            except Exception as exc:
                print(f"[reload] obsidian rebuild warning: {exc}")

        from app.git_backup_service import GitBackupService
        git_backup_service = GitBackupService(
            repo_path=Path.cwd(),
            enabled=chat_service.config.git_backup_enabled if chat_service else True,
            interval_minutes=chat_service.config.git_backup_interval_minutes if chat_service else 60,
        )
        git_backup_service.start()

        print("[reload] completed")
        _blog.log("events", "Reload completed")
        if old_blog is not None and old_blog is not _blog.get_default():
            old_blog.close()


async def _do_shutdown() -> None:
    await _do_cleanup()
    await asyncio.sleep(0.3)
    signal.raise_signal(signal.SIGINT)


# ---------------------------------------------------------------------------
# PID file for external process managers (GUI launcher)
# ---------------------------------------------------------------------------

_PID_FILE = Path("logs/0x010.pid")


def _resolve_port() -> int | None:
    for i, arg in enumerate(sys.argv):
        if arg == "--port" and i + 1 < len(sys.argv):
            try:
                return int(sys.argv[i + 1])
            except ValueError:
                return None
        if arg.startswith("--port="):
            try:
                return int(arg.split("=", 1)[1])
            except ValueError:
                return None
    return None


def _write_pid_file() -> None:
    try:
        payload = {
            "pid": os.getpid(),
            "port": _resolve_port(),
            "started_at": utc_now_iso(),
        }
        _PID_FILE.parent.mkdir(parents=True, exist_ok=True)
        _PID_FILE.write_text(json.dumps(payload), encoding="utf-8")
    except OSError:
        pass


def _remove_pid_file() -> None:
    try:
        _PID_FILE.unlink(missing_ok=True)
    except OSError:
        pass


# SSE helper

def _sse(event: dict[str, Any]) -> str:
    return f"data: {json.dumps(event, ensure_ascii=False)}\n\n"


# Time helpers

def _utc_now() -> str:
    return utc_now_iso()


def _utc_timestamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")


def _sync_runtime_history(chat_service: ChatService, chat) -> None:
    runtime_msgs = [
        {"role": m.role, "content": m.content}
        for m in chat.messages
        if m.role in ("user", "assistant") and m.status == "complete"
    ]
    chat_service.sync_runtime_history(runtime_msgs)


def _format_committed_memory(memory: dict[str, Any]) -> str:
    items = memory.get("items", []) if isinstance(memory, dict) else []
    if not items:
        return "No committed memory items."
    lines = ["**Committed memory:**", ""]
    for i, item in enumerate(items, 1):
        text = item.get("text", "")
        kind = item.get("kind", "unknown")
        subject = item.get("subject", "unknown")
        confidence = item.get("confidence", "unknown")
        lines.append(f"{i}. **{kind}** ({subject}, {confidence}): {text}")
    return "\n".join(lines)


