def _read_last_review_log_entry(chat_service: ChatService | None) -> dict[str, Any] | None:
    if chat_service is None:
        return None
    log_path = chat_service.config.standard_memory_review_log_path
    if not log_path.exists():
        return None
    try:
        with open(log_path, "rb") as f:
            f.seek(0, 2)
            end = f.tell()
            buf_size = min(4096, end)
            if buf_size == 0:
                return None
            f.seek(-buf_size, 2)
            buf = f.read(buf_size)
        lines = [line.strip() for line in buf.decode("utf-8", errors="replace").splitlines() if line.strip()]
        if not lines:
            return None
        last = json.loads(lines[-1])
        applied = last.get("applied", {})
        return {
            "at": last.get("timestamp") or last.get("ts"),
            "items_reviewed": applied.get("committed", 0) + applied.get("discarded", 0) + applied.get("held", 0),
        }
    except Exception:
        return None


@app.get("/api/status")
async def api_status() -> dict[str, Any]:
    if chat_service is None:
        raise HTTPException(status_code=503, detail="Backend not ready")
    memory_items = []
    if isinstance(chat_service.memory, dict):
        memory_items = chat_service.memory.get("items", []) or []
    due = []
    if chat_service.proactive_service is not None and chat_service.config.proactive_enabled:
        due = [r.to_dict() for r in chat_service.proactive_service.due_reminders()]
    tg_user_summary = None
    if tg_user_bridge is not None:
        try:
            tg_user_summary = tg_user_bridge.status()
        except Exception:
            pass
    telegram_bot_summary = None
    try:
        telegram_bot_summary = chat_service.telegram_status()
    except Exception:
        pass
    sleep_summary = None
    try:
        sleep_summary = chat_service.get_sleep_status()
    except Exception:
        pass
    activity_summary = None
    try:
        acfg = chat_service.get_activity_config_snapshot()
        activity_summary = {"mode": acfg.get("mode", "off"), "enabled": acfg.get("mode", "off") != "off"}
    except Exception:
        pass
    notes_count = 0
    global _status_notes_cache
    now = time.time()
    if _status_notes_cache is not None and now - _status_notes_cache[1] < 10:
        notes_count = _status_notes_cache[0]
    else:
        try:
            notes_count = len(chat_service.list_notes())
        except Exception:
            pass
        _status_notes_cache = (notes_count, now)
    last_turn_budget = None
    if chat_service.last_prompt_budget is not None:
        b = chat_service.last_prompt_budget
        used = b.get("estimated_tokens", 0)
        max_t = chat_service.config.max_prompt_tokens
        last_turn_budget = {
            "used": used,
            "max": max_t,
            "reductions": b.get("reductions", []),
            "percent": min(100, round((used / max_t) * 100)) if max_t else 0,
        }
    git_commit_summary = None
    if git_backup_service is not None:
        try:
            gs = git_backup_service.status()
            if gs.get("last_commit"):
                git_commit_summary = gs["last_commit"]
        except Exception:
            pass
    return {
        "mode": chat_service.config.mode,
        "model_name": chat_service.get_loaded_model_name(),
        "reasoning_policy": chat_service.config.chat_reasoning_policy,
        "vector_mode": chat_service.config.memory_vector_mode,
        "server_online": chat_service is not None,
        "committed_memory_count": len(memory_items),
        "due_reminders": due,
        "pipeline_counts": {
            "committed": len(memory_items),
            "candidates": len(chat_service.candidates.get("items", [])) if isinstance(chat_service.candidates, dict) else 0,
            "inbox": len(chat_service.inbox.get("items", [])) if isinstance(chat_service.inbox, dict) else 0,
            "held": len(chat_service.held.get("items", [])) if isinstance(chat_service.held, dict) else 0,
            "notes": notes_count,
        },
        "integrations": {
            "telegram_bot": {
                "running": telegram_bot_summary.get("running", False) if telegram_bot_summary else False,
                "enabled": telegram_bot_summary.get("enabled", False) if telegram_bot_summary else False,
            },
            "telegram_user": {
                "running": tg_user_summary.get("running", False) if tg_user_summary else False,
                "enabled": tg_user_summary.get("enabled", False) if tg_user_summary else False,
            },
            "web_search": {"enabled": chat_service.config.web_search_enabled},
            "activity": activity_summary or {"mode": "off", "enabled": False},
            "sleep": {
                "enabled": sleep_summary.get("enabled", False) if sleep_summary else False,
                "watcher_running": sleep_summary.get("watcher_running", False) if sleep_summary else False,
            },
        },
        "last_runs": {
            "sleep": {"at": sleep_summary.get("last_run_ts"), "status": "ok"} if sleep_summary and sleep_summary.get("last_run_ts") else None,
            "git_commit": git_commit_summary,
            "review": _read_last_review_log_entry(chat_service),
        },
        "last_turn_budget": last_turn_budget,
    }


