@app.post("/api/memory/review")
async def api_memory_review(body: dict[str, Any]) -> dict[str, Any]:
    if chat_service is None:
        raise HTTPException(status_code=503, detail="Backend not ready")
    decisions = body.get("decisions", [])
    if not isinstance(decisions, list):
        raise HTTPException(status_code=400, detail="decisions must be a list")
    # Normalize frontend schema (id -> candidate_id, hold -> keep_candidate)
    normalized: list[dict[str, Any]] = []
    for d in decisions:
        if not isinstance(d, dict):
            continue
        action = str(d.get("action", "")).strip().casefold()
        if action == "hold":
            action = "keep_candidate"
        cid = str(d.get("id", d.get("candidate_id", ""))).strip()
        if not cid:
            continue
        normalized.append({
            "candidate_id": cid,
            "action": action,
            "reason": str(d.get("reason", "")),
        })
    return chat_service.apply_memory_review(normalized)


