@app.post("/api/chats/{chat_id}/messages/stream")
async def stream_message(chat_id: str, body: dict[str, Any]) -> StreamingResponse:
    if chat_store is None or backend is None or chat_service is None:
        raise HTTPException(status_code=503, detail="Backend not ready")

    try:
        chat = chat_store.load_chat(chat_id)
    except WebChatStoreError:
        raise HTTPException(status_code=404, detail="Chat not found")

    user_text = str(body.get("content", "")).strip()
    if not user_text:
        raise HTTPException(status_code=400, detail="Message is empty")

    edit_message_id = str(body.get("edit_message_id", "")).strip()

    lock = await _get_chat_lock(chat_id)

    async def event_generator():
        nonlocal chat
        async with lock:
            # Switch runtime to this chat's session
            chat_service.switch_session(chat.runtime_session_id)
            _sync_runtime_history(chat_service, chat)

            if not edit_message_id and not bool(body.get("obsidian_snap")):
                # Record user message in web transcript
                user_msg = WebChatMessage(
                    id=f"msg_{_utc_timestamp()}_u",
                    role="user",
                    content=user_text,
                    status="complete",
                    created_at=_utc_now(),
                    updated_at=_utc_now(),
                )
                chat = chat_store.append_message(chat_id, user_msg)

            assistant_msg_id = f"msg_{_utc_timestamp()}_a"
            yield _sse({"type": "start", "chat_id": chat_id, "message_id": assistant_msg_id})

            start_ts = datetime.now(timezone.utc)
            user_message_count = sum(1 for m in chat.messages if m.role == "user")
            assistant_message_count = sum(1 for m in chat.messages if m.role == "assistant")
            try:
                req = BackendRequest(
                    kind="message",
                    text=user_text,
                    chat_id=chat_id,
                    client="web",
                    context_items=body.get("context_items", []),
                    web_search=body.get("web_search"),
                    image_attachments=body.get("image_attachments"),
                    metadata={
                        "title_source": chat.title_source,
                        "user_message_count": user_message_count,
                        "assistant_message_count": assistant_message_count,
                        "active_skill": str(body.get("active_skill", "")).strip(),
                        "obsidian_snap": bool(body.get("obsidian_snap")),
                        "deep_search": bool(body.get("deep_search")),
                    },
                )
                resp = backend.handle(req)

                if not resp.ok:
                    yield _sse({"type": "error", "message": resp.reply})
                    chat_store.append_message(chat_id, WebChatMessage(
                        id=assistant_msg_id,
                        role="assistant",
                        content="",
                        status="error",
                        error_message=resp.reply,
                        created_at=_utc_now(),
                        updated_at=_utc_now(),
                    ))
                    return

                reply = resp.reply
                if resp.chat_title:
                    title = resp.chat_title.get("title", "")
                    if title:
                        chat.title = title[:60]
                        chat.title_source = resp.chat_title.get("source", "auto")
                        chat_store._save_chat(chat)
                        yield _sse({"type": "chat_title", "title": chat.title, "source": chat.title_source})
                if resp.reasoning:
                    yield _sse({"type": "reasoning", "text": resp.reasoning})
                # v1: emit full reply as one token chunk
                yield _sse({"type": "token", "text": reply})

                metadata: dict[str, Any] = {}
                if resp.reasoning:
                    metadata["reasoning"] = resp.reasoning
                if resp.diagnostics and resp.diagnostics.get("guardrail_type"):
                    metadata["guardrail_type"] = resp.diagnostics["guardrail_type"]
                if resp.diagnostics and resp.diagnostics.get("context_used"):
                    metadata["context_used"] = resp.diagnostics["context_used"]
                if resp.web_search_trace:
                    metadata["web_search_trace"] = resp.web_search_trace
                if resp.tool_trace:
                    metadata["tool_trace"] = resp.tool_trace

                trace: dict[str, Any] = {
                    "memory_items": [
                        {"id": item.get("id"), "text": str(item.get("text", ""))[:200]}
                        for item in (chat_service.last_memory_used or [])
                    ],
                    "evidence": [
                        {"type": c.get("type"), "source": c.get("source_ref") or c.get("id"), "excerpt": str(c.get("title", ""))[:200], "trust_level": c.get("trust_level"), "scope": c.get("scope")}
                        for c in ((resp.diagnostics or {}).get("context_used") or [])
                        if c.get("type") not in ("guardrail", "memory", "task_state", "interaction_state")
                    ],
                    "context_sources": [
                        {"type": c.get("type"), "title": c.get("title"), "source_ref": c.get("source_ref"), "trust_level": c.get("trust_level"), "scope": c.get("scope")}
                        for c in ((resp.diagnostics or {}).get("context_used") or [])
                    ],
                    "tool_calls": [
                        {"name": ev.get("tool_name"), "status": "success" if ev.get("ok") else "error", "args": str(ev.get("metadata", {}))[:200]}
                        for ev in (resp.tool_trace or {}).get("events", [])
                    ],
                    "pipeline_counts": {
                        "inbox": len(chat_service.inbox.get("items", [])) if isinstance(chat_service.inbox, dict) else 0,
                        "candidates": len(chat_service.candidates.get("items", [])) if isinstance(chat_service.candidates, dict) else 0,
                        "held": len(chat_service.held.get("items", [])) if isinstance(chat_service.held, dict) else 0,
                        "committed": len(chat_service.memory.get("items", [])) if isinstance(chat_service.memory, dict) else 0,
                    },
                }
                if chat_service.last_prompt_budget is not None:
                    trace["prompt_budget"] = {
                        "max_tokens": chat_service.config.max_prompt_tokens,
                        "estimated_tokens": chat_service.last_prompt_budget.get("estimated_tokens", 0),
                        "static_tokens": chat_service.last_prompt_budget.get("static_tokens", 0),
                        "user_tokens": chat_service.last_prompt_budget.get("user_tokens", 0),
                        "history_tokens": chat_service.last_prompt_budget.get("history_tokens", 0),
                        "memory_tokens": chat_service.last_prompt_budget.get("memory_tokens", 0),
                        "notes_tokens": chat_service.last_prompt_budget.get("notes_tokens", 0),
                        "evidence_tokens": chat_service.last_prompt_budget.get("evidence_tokens", 0),
                        "reductions": chat_service.last_prompt_budget.get("reductions", []),
                    }
                details = chat_service.last_generation_details
                if details is not None:
                    trace["reasoning"] = {
                        "enabled": chat_service.config.chat_reasoning_policy != "off",
                        "budget": chat_service.config.chat_reasoning_budget,
                        "text_length": len(details.reasoning_text or ""),
                        "detected": details.reasoning_detected or False,
                    }
                metadata["trace"] = trace

                total_ms = int((datetime.now(timezone.utc) - start_ts).total_seconds() * 1000)
                yield _sse({
                    "type": "metrics",
                    "total_ms": total_ms,
                    "chars": len(reply),
                    "token_count_mode": "approximate",
                })
                if metadata:
                    yield _sse({"type": "metadata", "metadata": metadata})
                yield _sse({"type": "done", "message_id": assistant_msg_id})

                chat_store.append_message(chat_id, WebChatMessage(
                    id=assistant_msg_id,
                    role="assistant",
                    content=reply,
                    status="complete",
                    created_at=_utc_now(),
                    updated_at=_utc_now(),
                    metadata=metadata,
                ))
            except Exception as exc:
                yield _sse({"type": "error", "message": str(exc)})
                chat_store.append_message(chat_id, WebChatMessage(
                    id=assistant_msg_id,
                    role="assistant",
                    content="",
                    status="error",
                    error_message=str(exc),
                    created_at=_utc_now(),
                    updated_at=_utc_now(),
                ))

    return StreamingResponse(
        event_generator(),
        media_type="text/event-stream",
        headers={"Cache-Control": "no-cache", "Connection": "keep-alive"},
    )


