async def patch_message(chat_id: str, message_id: str, body: dict[str, Any]) -> dict[str, Any]:
    if chat_store is None or chat_service is None:
        raise HTTPException(status_code=503, detail="Backend not ready")
    try:
        chat = chat_store.load_chat(chat_id)
    except WebChatStoreError:
        raise HTTPException(status_code=404, detail="Chat not found")
    idx = None
    for i, m in enumerate(chat.messages):
        if m.id == message_id:
            idx = i
            break
    if idx is None:
        raise HTTPException(status_code=404, detail="Message not found")
    content = body.get("content")
    if content is not None:
        chat.messages[idx].content = str(content)
        chat.messages[idx].updated_at = _utc_now()
    if content is not None and chat.messages[idx].role == "user":
        chat.messages = chat.messages[: idx + 1]
    chat.updated_at = _utc_now()
    chat_store._save_chat(chat)
    chat_service.switch_session(chat.runtime_session_id)
    _sync_runtime_history(chat_service, chat)
    return chat.to_dict()


