@app.post("/api/commands")
async def run_command(body: dict[str, Any]) -> dict[str, Any]:
    if backend is None:
        raise HTTPException(status_code=503, detail="Backend not ready")

    cmd = str(body.get("command", "")).strip().lower()
    if not cmd:
        raise HTTPException(status_code=400, detail="command is required")

    chat_id = body.get("chat_id")
    extra = {k: v for k, v in body.items() if k not in ("command", "chat_id")}
    text = str(body["text"]) if "text" in body else (json.dumps(extra) if extra else "")
    if chat_id and chat_store is not None:
        try:
            chat = chat_store.load_chat(chat_id)
        except WebChatStoreError:
            raise HTTPException(status_code=404, detail="Chat not found")
        lock = await _get_chat_lock(chat_id)
        async with lock:
            chat_service.switch_session(chat.runtime_session_id)
            _sync_runtime_history(chat_service, chat)
            req = BackendRequest(
                kind="command",
                command=cmd,
                text=text,
                chat_id=chat_id,
                client="web",
            )
            resp = backend.handle(req)
            if resp.ok and cmd in ("/reset", "reset"):
                chat_service.reload_resources()
    else:
        req = BackendRequest(kind="command", command=cmd, text=text, client="web")
        resp = backend.handle(req)
        if resp.ok and cmd in ("/reset", "reset"):
            chat_service.reload_resources()

    return resp.to_dict()


