@app.get("/api/notes/{note_id}/backlinks")
async def api_note_backlinks(note_id: str) -> dict[str, Any]:
    if chat_service is None:
        raise HTTPException(status_code=503, detail="Backend not ready")
    cfg = chat_service.config
    if not cfg.obsidian_vault_enabled:
        raise HTTPException(status_code=400, detail="Obsidian vault not enabled")
    notes_dir = cfg.obsidian_vault_path / cfg.obsidian_notes_subdir
    if not notes_dir.exists():
        return {"backlinks": []}

    safe_id = re.sub(r"[^\w\-]", "", note_id)
    if not safe_id:
        raise HTTPException(status_code=400, detail="Invalid note_id")

    def _run() -> dict[str, Any]:
        from app.link_graph import LinkGraph
        graph = LinkGraph(notes_dir)
        edges = graph.backlinks_for(safe_id)
        backlinks: list[dict[str, str]] = []
        seen: set[str] = set()
        for edge in edges:
            source_id = edge.source_id
            if source_id in seen:
                continue
            seen.add(source_id)
            source_path = notes_dir / f"{source_id}.md"
            title = source_id
            excerpt = ""
            if source_path.exists():
                try:
                    text = source_path.read_text(encoding="utf-8")
                    lines = text.splitlines()
                    for line in lines:
                        stripped = line.strip()
                        if stripped.startswith("# "):
                            title = stripped[2:].strip()
                            break
                        if stripped:
                            title = stripped
                            break
                    excerpt = text[:120]
                except OSError:
                    pass
            backlinks.append({"id": source_id, "title": title, "excerpt": excerpt})
        return {"backlinks": backlinks}

    return await run_in_threadpool(_run)


