STANDARD_COMMITTED_MEMORY_NAMESPACE = "standard_committed_memory"


class EmbeddingClientError(Exception):
    """Raised when an embedding request cannot be completed."""


class VectorStoreError(Exception):
    """Raised when vector storage cannot be used."""


class EmbeddingClient(Protocol):
    model_id: str
    dimensions: int | None

    def embed_texts(self, texts: list[str]) -> list[list[float]]:
        """Return one embedding vector for each input text."""


class VectorStore(Protocol):
    def available(self) -> bool:
        """Return whether the store can be used in the current environment."""

    def ensure_schema(self, *, dimensions: int) -> None:
        """Create/validate storage schema for the configured embedding dimensions."""

    def upsert(self, records: list["VectorMemoryRecord"]) -> None:
        """Insert or replace indexed records."""

    def delete_missing(self, *, namespace: str, source_paths: set[str]) -> None:
        """Delete records in namespace whose source path is no longer present."""

    def delete_by_source_path(self, *, namespace: str, source_path: str) -> None:
        """Delete the single record matching namespace + source_path."""

    def indexed_metadata(self, *, namespace: str) -> dict[str, dict[str, Any]]:
        """Return source_path -> stored metadata for incremental rebuild decisions."""

    def search(
        self,
        *,
        namespace: str,
        query_embedding: list[float],
        limit: int,
    ) -> list["VectorMemoryHit"]:
        """Return nearest records for query embedding."""


