class OpenAICompatibleEmbeddingClient:
    def __init__(
        self,
        *,
        base_url: str,
        model_name: str,
        api_key: str = "local-server",
        timeout: float | None = 60.0,
        max_chars_per_text: int = 1500,
    ) -> None:
        cleaned_model = str(model_name or "").strip()
        if not cleaned_model:
            raise EmbeddingClientError("EMBEDDINGS_MODEL_NAME не должен быть пустым для live embeddings.")
        self.model_id = cleaned_model
        self.dimensions: int | None = None
        self.max_chars_per_text = max_chars_per_text
        self._client = OpenAI(
            base_url=str(base_url or "").strip(),
            api_key=api_key or "local-server",
            timeout=timeout,
        )

    def embed_texts(self, texts: list[str]) -> list[list[float]]:
        cleaned = [str(text or "")[:self.max_chars_per_text] for text in texts]
        if not cleaned:
            return []
        try:
            response = self._client.embeddings.create(
                model=self.model_id,
                input=cleaned,
            )
        except Exception as error:  # noqa: BLE001 - fail-soft caller decides fallback behavior.
            raise EmbeddingClientError(f"Не удалось получить embeddings: {error}") from error
        response_items = list(getattr(response, "data", []) or [])
        if any(_embedding_response_index(item) is not None for item in response_items):
            response_items.sort(key=lambda item: _embedding_response_index(item) if _embedding_response_index(item) is not None else 0)
        vectors: list[list[float]] = []
        for item in response_items:
            vector = getattr(item, "embedding", None)
            if vector is None and isinstance(item, dict):
                vector = item.get("embedding")
            if not isinstance(vector, list):
                raise EmbeddingClientError("Embedding endpoint вернул некорректный vector payload.")
            vectors.append([float(value) for value in vector])
        if len(vectors) != len(cleaned):
            raise EmbeddingClientError("Embedding endpoint вернул не то количество vectors.")
        if vectors:
            self.dimensions = len(vectors[0])
        return vectors


