class InMemoryVectorStore:
    """Simple cosine-search store used by unit tests; not persisted."""

    def __init__(self) -> None:
        self.records: dict[tuple[str, str], VectorMemoryRecord] = {}
        self.dimensions: int | None = None

    def available(self) -> bool:
        return True

    def ensure_schema(self, *, dimensions: int) -> None:
        if dimensions <= 0:
            raise VectorStoreError("Vector dimensions must be positive.")
        if self.dimensions is not None and self.dimensions != dimensions:
            raise VectorStoreError("Vector dimensions mismatch.")
        self.dimensions = dimensions

    def upsert(self, records: list[VectorMemoryRecord]) -> None:
        for record in records:
            self.ensure_schema(dimensions=record.dimensions)
            self.records[(record.namespace, record.source_path)] = record

    def delete_missing(self, *, namespace: str, source_paths: set[str]) -> None:
        for key in list(self.records):
            if key[0] == namespace and key[1] not in source_paths:
                del self.records[key]

    def delete_by_source_path(self, *, namespace: str, source_path: str) -> None:
        key = (namespace, source_path)
        if key in self.records:
            del self.records[key]

    def indexed_metadata(self, *, namespace: str) -> dict[str, dict[str, Any]]:
        return {
            source_path: {
                "item_id": record.item_id,
                "text_hash": record.text_hash,
                "embedding_model_id": record.embedding_model_id,
                "dimensions": record.dimensions,
            }
            for (record_namespace, source_path), record in self.records.items()
            if record_namespace == namespace
        }

    def search(
        self,
        *,
        namespace: str,
        query_embedding: list[float],
        limit: int,
    ) -> list[VectorMemoryHit]:
        if limit <= 0:
            return []
        hits: list[VectorMemoryHit] = []
        for record in self.records.values():
            if record.namespace != namespace:
                continue
            score = _cosine_similarity(query_embedding, record.embedding)
            hits.append(
                VectorMemoryHit(
                    namespace=record.namespace,
                    item_id=record.item_id,
                    source_path=record.source_path,
                    text=record.text,
                    score=score,
                    embedding_model_id=record.embedding_model_id,
                    dimensions=record.dimensions,
                    text_hash=record.text_hash,
                    updated_at=record.updated_at,
                )
            )
        hits.sort(key=lambda hit: hit.score, reverse=True)
        return hits[:limit]


class SqliteVecVectorStore:
    """sqlite-vec adapter. Schema is an adapter detail, not the memory format."""

    def __init__(self, db_path: Path) -> None:
        self.db_path = Path(db_path)
        self._sqlite_vec: Any | None = None
        self._import_error: Exception | None = None
        self._distance_metric_cached: str | None = None
        try:
            import sqlite_vec  # type: ignore[import-not-found]
        except Exception as error:  # noqa: BLE001 - optional dependency.
            self._import_error = error
        else:
            self._sqlite_vec = sqlite_vec

    def available(self) -> bool:
        return self._sqlite_vec is not None

    def close(self) -> None:
        """No-op: connections are scoped per-operation via _connect()."""

    def _distance_metric(self) -> str:
        if self._distance_metric_cached is not None:
            return self._distance_metric_cached
        if not self.db_path.exists():
            self._distance_metric_cached = "cosine"
            return self._distance_metric_cached
        with self._connect() as conn:
            row = conn.execute(
                "SELECT sql FROM sqlite_master WHERE type='table' AND name='vector_memory_embeddings'"
            ).fetchone()
        if row and row[0] and "distance_metric=cosine" in row[0]:
            self._distance_metric_cached = "cosine"
        else:
            self._distance_metric_cached = "l2"
        return self._distance_metric_cached

    def ensure_schema(self, *, dimensions: int) -> None:
        if dimensions <= 0:
            raise VectorStoreError("Vector dimensions must be positive.")
        with self._connect() as conn:
            conn.execute(
                "CREATE TABLE IF NOT EXISTS vector_memory_meta "
                "(key TEXT PRIMARY KEY, value TEXT NOT NULL)"
            )
            existing_dimensions = conn.execute(
                "SELECT value FROM vector_memory_meta WHERE key = 'dimensions'"
            ).fetchone()
            if existing_dimensions is not None and int(existing_dimensions[0]) != dimensions:
                raise VectorStoreError(
                    "Vector DB dimensions mismatch; rebuild or use another MEMORY_VECTOR_DB_PATH."
                )
            conn.execute(
                "CREATE TABLE IF NOT EXISTS vector_memory_items ("
                "rowid INTEGER PRIMARY KEY AUTOINCREMENT, "
                "namespace TEXT NOT NULL, "
                "item_id TEXT NOT NULL, "
                "source_path TEXT NOT NULL, "
                "text TEXT NOT NULL, "
                "text_hash TEXT NOT NULL, "
                "embedding_model_id TEXT NOT NULL, "
                "dimensions INTEGER NOT NULL, "
                "updated_at TEXT NOT NULL, "
                "UNIQUE(namespace, source_path))"
            )
            conn.execute(
                f"CREATE VIRTUAL TABLE IF NOT EXISTS vector_memory_embeddings "
                f"USING vec0(embedding float[{dimensions}] distance_metric=cosine)"
            )
            conn.execute(
                "INSERT OR REPLACE INTO vector_memory_meta(key, value) VALUES ('dimensions', ?)",
                (str(dimensions),),
            )
            conn.commit()

    def upsert(self, records: list[VectorMemoryRecord]) -> None:
        if not records:
            return
        dimensions = records[0].dimensions
        self.ensure_schema(dimensions=dimensions)
        with self._connect() as conn:
            for record in records:
                if record.dimensions != dimensions:
                    raise VectorStoreError("Cannot mix embedding dimensions in one upsert.")
                row = conn.execute(
                    "SELECT rowid, item_id, text_hash, embedding_model_id, dimensions FROM vector_memory_items "
                    "WHERE namespace = ? AND source_path = ?",
                    (record.namespace, record.source_path),
                ).fetchone()
                if (
                    row is not None
                    and row[1] == record.item_id
                    and row[2] == record.text_hash
                    and row[3] == record.embedding_model_id
                    and int(row[4]) == record.dimensions
                ):
                    continue
                if row is None:
                    cursor = conn.execute(
                        "INSERT INTO vector_memory_items "
                        "(namespace, item_id, source_path, text, text_hash, embedding_model_id, dimensions, updated_at) "
                        "VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                        (
                            record.namespace,
                            record.item_id,
                            record.source_path,
                            record.text,
                            record.text_hash,
                            record.embedding_model_id,
                            record.dimensions,
                            record.updated_at,
                        ),
                    )
                    rowid = int(cursor.lastrowid)
                else:
                    rowid = int(row[0])
                    conn.execute(
                        "UPDATE vector_memory_items SET item_id = ?, text = ?, text_hash = ?, "
                        "embedding_model_id = ?, dimensions = ?, updated_at = ? WHERE rowid = ?",
                        (
                            record.item_id,
                            record.text,
                            record.text_hash,
                            record.embedding_model_id,
                            record.dimensions,
                            record.updated_at,
                            rowid,
                        ),
                    )
                    conn.execute("DELETE FROM vector_memory_embeddings WHERE rowid = ?", (rowid,))
                conn.execute(
                    "INSERT INTO vector_memory_embeddings(rowid, embedding) VALUES (?, ?)",
                    (rowid, self._serialize_vector(record.embedding)),
                )
            conn.commit()

    def delete_missing(self, *, namespace: str, source_paths: set[str]) -> None:
        if not self.db_path.exists():
            return
        placeholders = ",".join("?" for _ in source_paths)
        params: list[str] = [namespace, *sorted(source_paths)]
        with self._connect() as conn:
            has_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'vector_memory_items'"
            ).fetchone()
            if not has_table:
                return
            if source_paths:
                rows = conn.execute(
                    f"SELECT rowid FROM vector_memory_items WHERE namespace = ? "
                    f"AND source_path NOT IN ({placeholders})",
                    params,
                ).fetchall()
            else:
                rows = conn.execute(
                    "SELECT rowid FROM vector_memory_items WHERE namespace = ?",
                    (namespace,),
                ).fetchall()
            for row in rows:
                rowid = int(row[0])
                conn.execute("DELETE FROM vector_memory_embeddings WHERE rowid = ?", (rowid,))
                conn.execute("DELETE FROM vector_memory_items WHERE rowid = ?", (rowid,))
            conn.commit()

    def delete_by_source_path(self, *, namespace: str, source_path: str) -> None:
        if not self.db_path.exists():
            return
        with self._connect() as conn:
            has_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'vector_memory_items'"
            ).fetchone()
            if not has_table:
                return
            row = conn.execute(
                "SELECT rowid FROM vector_memory_items WHERE namespace = ? AND source_path = ?",
                (namespace, source_path),
            ).fetchone()
            if row:
                rowid = int(row[0])
                conn.execute("DELETE FROM vector_memory_embeddings WHERE rowid = ?", (rowid,))
                conn.execute("DELETE FROM vector_memory_items WHERE rowid = ?", (rowid,))
                conn.commit()

    def indexed_metadata(self, *, namespace: str) -> dict[str, dict[str, Any]]:
        if not self.db_path.exists():
            return {}
        with self._connect() as conn:
            has_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'vector_memory_items'"
            ).fetchone()
            has_embeddings_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE name = 'vector_memory_embeddings'"
            ).fetchone()
            if not has_table or not has_embeddings_table:
                return {}
            rows = conn.execute(
                "SELECT d.source_path, d.item_id, d.text_hash, d.embedding_model_id, d.dimensions "
                "FROM vector_memory_items d JOIN vector_memory_embeddings v ON d.rowid = v.rowid "
                "WHERE d.namespace = ?",
                (namespace,),
            ).fetchall()
        return {
            str(row[0]): {
                "item_id": str(row[1]),
                "text_hash": str(row[2]),
                "embedding_model_id": str(row[3]),
                "dimensions": int(row[4]),
            }
            for row in rows
        }

    def search(
        self,
        *,
        namespace: str,
        query_embedding: list[float],
        limit: int,
    ) -> list[VectorMemoryHit]:
        if limit <= 0 or not self.db_path.exists():
            return []
        with self._connect() as conn:
            has_items_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'vector_memory_items'"
            ).fetchone()
            has_embeddings_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE name = 'vector_memory_embeddings'"
            ).fetchone()
            if not has_items_table or not has_embeddings_table:
                return []
            rows = conn.execute(
                "SELECT d.namespace, d.item_id, d.source_path, d.text, v.distance, "
                "d.embedding_model_id, d.dimensions, d.text_hash, d.updated_at "
                "FROM vector_memory_embeddings v "
                "JOIN vector_memory_items d ON d.rowid = v.rowid "
                "WHERE d.namespace = ? AND v.embedding MATCH ? AND k = ? "
                "ORDER BY v.distance",
                (namespace, self._serialize_vector(query_embedding), int(limit)),
            ).fetchall()
        return [
            VectorMemoryHit(
                namespace=str(row[0]),
                item_id=str(row[1]),
                source_path=str(row[2]),
                text=str(row[3]),
                score=1.0 - float(row[4]) if self._distance_metric() == "cosine" else -float(row[4]),
                embedding_model_id=str(row[5]),
                dimensions=int(row[6]),
                text_hash=str(row[7]),
                updated_at=str(row[8]),
            )
            for row in rows
        ]

    @contextmanager
    def _connect(self):
        if self._sqlite_vec is None:
            raise VectorStoreError(f"sqlite-vec is not available: {self._import_error}")
        self.db_path.parent.mkdir(parents=True, exist_ok=True)
        conn = sqlite3.connect(str(self.db_path))
        try:
            try:
                conn.enable_load_extension(True)
                self._sqlite_vec.load(conn)
            finally:
                conn.enable_load_extension(False)
            yield conn
        except Exception as error:  # noqa: BLE001 - normalize optional adapter failures.
            raise VectorStoreError(f"Не удалось загрузить sqlite-vec extension: {error}") from error
        finally:
            conn.close()

    def _serialize_vector(self, vector: list[float]) -> bytes:
        if self._sqlite_vec is None:
            raise VectorStoreError("sqlite-vec is not available.")
        return self._sqlite_vec.serialize_float32([float(value) for value in vector])


class StandardVectorMemoryRetriever:
    def __init__(self, *, embedding_client: EmbeddingClient, store: VectorStore) -> None:
        self.embedding_client = embedding_client
        self.store = store
        self.last_rebuild_stats: dict[str, int] = {
            "committed_count": 0,
            "embedded_count": 0,
            "skipped_unchanged_count": 0,
        }

    def rebuild_standard_committed_memory_index(
        self,
        memory: dict[str, Any],
        *,
        source_paths_by_id: dict[str, str] | None = None,
    ) -> int:
        items = memory.get("items", []) if isinstance(memory, dict) else []
        normalized_items = [item for item in items if _is_committed_memory_item(item)]
        source_paths = {
            _memory_item_source_path(item, source_paths_by_id=source_paths_by_id)
            for item in normalized_items
        }
        if not normalized_items:
            self.store.delete_missing(
                namespace=STANDARD_COMMITTED_MEMORY_NAMESPACE,
                source_paths=set(),
            )
            self.last_rebuild_stats = {
                "committed_count": 0,
                "embedded_count": 0,
                "skipped_unchanged_count": 0,
            }
            return 0

        indexed = self.store.indexed_metadata(namespace=STANDARD_COMMITTED_MEMORY_NAMESPACE)
        records_to_embed: list[tuple[dict[str, Any], str, str, str]] = []
        for item in normalized_items:
            item_id = str(item.get("id", "")).strip()
            text = _record_text(item)
            source_path = _memory_item_source_path(item, source_paths_by_id=source_paths_by_id)
            text_hash = hash_text(text)
            metadata = indexed.get(source_path)
            if (
                metadata
                and metadata.get("item_id") == item_id
                and metadata.get("text_hash") == text_hash
                and metadata.get("embedding_model_id") == self.embedding_client.model_id
                and (
                    self.embedding_client.dimensions is None
                    or metadata.get("dimensions") == self.embedding_client.dimensions
                )
            ):
                continue
            records_to_embed.append((item, text, source_path, text_hash))

        if records_to_embed:
            records = build_standard_committed_memory_records_from_prepared(
                records_to_embed,
                embedding_client=self.embedding_client,
            )
            self.store.ensure_schema(dimensions=records[0].dimensions)
            self.store.upsert(records)
        self.store.delete_missing(
            namespace=STANDARD_COMMITTED_MEMORY_NAMESPACE,
            source_paths=source_paths,
        )
        self.last_rebuild_stats = {
            "committed_count": len(normalized_items),
            "embedded_count": len(records_to_embed),
            "skipped_unchanged_count": len(normalized_items) - len(records_to_embed),
        }
        return len(normalized_items)

    def search_standard_committed_memory_hits(
        self,
        query: str,
        *,
        limit: int,
    ) -> list[VectorMemoryHit]:
        if limit <= 0 or not self.store.available():
            return []
        cleaned_query = str(query or "").strip()
        if not cleaned_query:
            return []
        query_embedding = self.embedding_client.embed_texts([cleaned_query])[0]
        return self.store.search(
            namespace=STANDARD_COMMITTED_MEMORY_NAMESPACE,
            query_embedding=query_embedding,
            limit=limit,
        )

    def search_standard_committed_memory(
        self,
        query: str,
        committed_items: list[dict[str, Any]],
        *,
        limit: int,
    ) -> list[dict[str, Any]]:
        return [
            item
            for item in self.search_standard_committed_memory_with_scores(
                query,
                committed_items,
                limit=limit,
            )
        ]

    def search_standard_committed_memory_with_scores(
        self,
        query: str,
        committed_items: list[dict[str, Any]],
        *,
        limit: int,
    ) -> list[dict[str, Any]]:
        hits = self.search_standard_committed_memory_hits(query, limit=limit)
        by_id = {str(item.get("id", "")): item for item in committed_items if isinstance(item, dict)}
        selected: list[dict[str, Any]] = []
        seen: set[str] = set()
        for rank, hit in enumerate(hits, start=1):
            item = by_id.get(hit.item_id)
            if item is None or hit.item_id in seen:
                continue
            seen.add(hit.item_id)
            selected_item = dict(item)
            selected_item["_retrieval_source"] = "vector"
            selected_item["_vector_rank"] = rank
            selected_item["_vector_score"] = hit.score
            selected.append(selected_item)
            if len(selected) >= limit:
                break
        return selected


def build_standard_vector_memory_retriever(config: AppConfig) -> StandardVectorMemoryRetriever:
    embedding_client = OpenAICompatibleEmbeddingClient(
        base_url=config.embeddings_base_url,
        model_name=config.embeddings_model_name,
        api_key=config.api_key or "local-server",
        timeout=60.0,
        max_chars_per_text=config.embeddings_max_chars,
    )
    store = SqliteVecVectorStore(config.memory_vector_db_path)
    return StandardVectorMemoryRetriever(
        embedding_client=embedding_client,
        store=store,
    )


def build_standard_committed_memory_records(
    memory: dict[str, Any],
    *,
    embedding_client: EmbeddingClient,
    source_paths_by_id: dict[str, str] | None = None,
) -> list[VectorMemoryRecord]:
    items = memory.get("items", []) if isinstance(memory, dict) else []
    normalized_items = [item for item in items if _is_committed_memory_item(item)]
    prepared: list[tuple[dict[str, Any], str, str, str]] = []
    for item in normalized_items:
        text = _record_text(item)
        prepared.append(
            (
                item,
                text,
                _memory_item_source_path(item, source_paths_by_id=source_paths_by_id),
                hash_text(text),
            )
        )
    return build_standard_committed_memory_records_from_prepared(
        prepared,
        embedding_client=embedding_client,
    )


def build_standard_committed_memory_records_from_prepared(
    prepared: list[tuple[dict[str, Any], str, str, str]],
    *,
    embedding_client: EmbeddingClient,
) -> list[VectorMemoryRecord]:
    texts = [text for _, text, _, _ in prepared]
    embeddings = embedding_client.embed_texts(texts)
    if len(embeddings) != len(prepared):
        raise EmbeddingClientError("Embedding client returned an unexpected vector count.")
    records: list[VectorMemoryRecord] = []
    for (item, text, source_path, text_hash), embedding in zip(prepared, embeddings, strict=True):
        item_id = str(item.get("id", "")).strip()
        dimensions = len(embedding)
        if dimensions <= 0:
            raise EmbeddingClientError("Embedding vector must not be empty.")
        records.append(
            VectorMemoryRecord(
                namespace=STANDARD_COMMITTED_MEMORY_NAMESPACE,
                item_id=item_id,
                source_path=source_path,
                text=text,
                text_hash=text_hash,
                embedding=[float(value) for value in embedding],
                embedding_model_id=embedding_client.model_id,
                dimensions=dimensions,
                updated_at=utc_now_iso(),
            )
        )
    return records


def read_standard_committed_note_paths(config: AppConfig) -> dict[str, str]:
    """Return committed memory item id -> markdown path from the source-of-truth vault."""
    result: dict[str, str] = {}
    for path in sorted(config.standard_memory_committed_dir.glob("*.md")):
        item_id = _read_markdown_note_id(path)
        if item_id:
            result[item_id] = str(path)
    return result


def read_standard_committed_memory_notes(config: AppConfig) -> dict[str, Any]:
    """Read committed markdown notes directly without updating the secondary snapshot."""
    items: list[dict[str, Any]] = []
    for path in sorted(config.standard_memory_committed_dir.glob("*.md")):
        item = _read_markdown_note_for_vector(path)
        if item:
            items.append(item)
    return {"items": items}


def inspect_standard_vector_index(
    config: AppConfig,
    memory: dict[str, Any],
    *,
    source_paths_by_id: dict[str, str] | None = None,
) -> dict[str, Any]:
    """Inspect sqlite metadata without requiring sqlite-vec extension or embedding server."""
    db_path = Path(config.memory_vector_db_path)
    items = [item for item in memory.get("items", []) if _is_committed_memory_item(item)] if isinstance(memory, dict) else []
    source_paths = source_paths_by_id if source_paths_by_id is not None else read_standard_committed_note_paths(config)
    expected_by_id = {str(item.get("id", "")).strip(): item for item in items}
    expected_hashes = {
        item_id: hash_text(_record_text(item))
        for item_id, item in expected_by_id.items()
    }
    status: dict[str, Any] = {
        "db_path": str(db_path),
        "db_exists": db_path.exists(),
        "namespace": STANDARD_COMMITTED_MEMORY_NAMESPACE,
        "committed_count": len(expected_by_id),
        "indexed_count": 0,
        "embeddings_table_exists": False,
        "missing_item_ids": sorted(expected_by_id),
        "extra_item_ids": [],
        "stale_item_ids": [],
        "embedding_model_ids": [],
        "dimensions": [],
        "ok": False,
    }
    if not db_path.exists():
        status["ok"] = not status["missing_item_ids"]
        return _attach_standard_vector_index_summary(status)
    try:
        conn = sqlite3.connect(str(db_path))
        try:
            has_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'vector_memory_items'"
            ).fetchone()
            has_embeddings_table = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE name = 'vector_memory_embeddings'"
            ).fetchone()
            status["embeddings_table_exists"] = bool(has_embeddings_table)
            if not has_table:
                status["ok"] = not status["missing_item_ids"]
                return _attach_standard_vector_index_summary(status)
            rows = conn.execute(
                "SELECT item_id, source_path, text_hash, embedding_model_id, dimensions "
                "FROM vector_memory_items WHERE namespace = ?",
                (STANDARD_COMMITTED_MEMORY_NAMESPACE,),
            ).fetchall()
        finally:
            conn.close()
    except sqlite3.Error as error:
        status["error"] = str(error)
        return _attach_standard_vector_index_summary(status)

    indexed_by_id = {str(row[0]): row for row in rows}
    indexed_ids = set(indexed_by_id)
    expected_ids = set(expected_by_id)
    stale_ids: list[str] = []
    for item_id in sorted(expected_ids & indexed_ids):
        row = indexed_by_id[item_id]
        indexed_path = str(row[1])
        indexed_hash = str(row[2])
        expected_path = source_paths.get(item_id)
        if indexed_hash != expected_hashes[item_id] or (expected_path and indexed_path != expected_path):
            stale_ids.append(item_id)
    status.update(
        {
            "indexed_count": len(indexed_ids),
            "missing_item_ids": sorted(expected_ids - indexed_ids),
            "extra_item_ids": sorted(indexed_ids - expected_ids),
            "stale_item_ids": stale_ids,
            "embedding_model_ids": sorted({str(row[3]) for row in rows if str(row[3])}),
            "dimensions": sorted({int(row[4]) for row in rows if row[4] is not None}),
        }
    )
    embeddings_ready = bool(status.get("embeddings_table_exists")) or not indexed_ids
    status["ok"] = (
        not status["missing_item_ids"]
        and not status["extra_item_ids"]
        and not status["stale_item_ids"]
        and embeddings_ready
    )
    if not embeddings_ready:
        status["stale_item_ids"] = sorted(expected_ids & indexed_ids)
    return _attach_standard_vector_index_summary(status)


def _attach_standard_vector_index_summary(status: dict[str, Any]) -> dict[str, Any]:
    if status.get("error"):
        state = "error"
    elif status.get("ok"):
        state = "ok"
    elif not status.get("db_exists"):
        state = "missing-db"
    else:
        state = "stale"
    model_ids = status.get("embedding_model_ids") or []
    dimensions = status.get("dimensions") or []
    model_part = ",".join(str(item) for item in model_ids) if model_ids else "<none>"
    dimensions_part = ",".join(str(item) for item in dimensions) if dimensions else "<none>"
    status["summary"] = (
        f"vector_index {state}: "
        f"committed={int(status.get('committed_count', 0) or 0)} "
        f"indexed={int(status.get('indexed_count', 0) or 0)} "
        f"missing={len(status.get('missing_item_ids') or [])} "
        f"stale={len(status.get('stale_item_ids') or [])} "
        f"extra={len(status.get('extra_item_ids') or [])} "
        f"model={model_part} dimensions={dimensions_part} "
        f"db={status.get('db_path', '')}"
    )
    return status


def hash_text(text: str) -> str:
    return hashlib.sha256(str(text or "").encode("utf-8")).hexdigest()


def _embedding_response_index(item: Any) -> int | None:
    value = getattr(item, "index", None)
    if value is None and isinstance(item, dict):
        value = item.get("index")
    try:
        return int(value) if value is not None else None
    except (TypeError, ValueError):
        return None


def _is_committed_memory_item(item: Any) -> bool:
    if not isinstance(item, dict):
        return False
    if str(item.get("status", "")).strip() != "committed":
        return False
    return bool(str(item.get("id", "")).strip() and str(item.get("text", "")).strip())


def _record_text(item: dict[str, Any]) -> str:
    parts = [str(item.get("text", "")).strip()]
    tags = item.get("tags", [])
    if isinstance(tags, list) and tags:
        cleaned_tags = [str(tag).strip() for tag in tags if str(tag).strip()]
        if cleaned_tags:
            parts.append("Tags: " + ", ".join(cleaned_tags))
    evidence = item.get("evidence", [])
    if isinstance(evidence, list) and evidence:
        cleaned_evidence = [str(entry).strip() for entry in evidence if str(entry).strip()]
        if cleaned_evidence:
            parts.append("Evidence: " + " | ".join(cleaned_evidence))
    return "\n".join(part for part in parts if part)


def _memory_item_source_path(
    item: dict[str, Any],
    *,
    source_paths_by_id: dict[str, str] | None = None,
) -> str:
    item_id = str(item.get("id", "")).strip()
    if source_paths_by_id and item_id in source_paths_by_id:
        return source_paths_by_id[item_id]
    metadata = item.get("metadata", {})
    if isinstance(metadata, dict):
        for key in ("path", "source_path"):
            value = str(metadata.get(key, "")).strip()
            if value:
                return value
    return f"standard/memory/committed/{item_id}.md"


def _read_markdown_note_id(path: Path) -> str:
    item = _read_markdown_note_for_vector(path, include_body=False)
    return str(item.get("id", "")).strip() if item else ""


def _read_markdown_note_for_vector(path: Path, *, include_body: bool = True) -> dict[str, Any] | None:
    try:
        text = path.read_text(encoding="utf-8")
    except OSError:
        return None
    if not text.startswith("---\n"):
        return None
    end = text.find("\n---\n", 4)
    if end == -1:
        return None
    frontmatter = _parse_simple_frontmatter(text[4:end])
    item_id = str(frontmatter.get("id", "")).strip()
    if not item_id:
        return None
    item_text = ""
    evidence = frontmatter.get("evidence", [])
    if include_body:
        body = text[end + 5 :].strip()
        item_text = _extract_markdown_note_text(body)
        body_evidence = _extract_markdown_note_evidence(body)
        if body_evidence:
            evidence = body_evidence
    else:
        item_text = str(frontmatter.get("text", "")).strip()
    if not item_text and include_body:
        return None
    return {
        "id": item_id,
        "status": "committed",
        "text": item_text,
        "evidence": evidence if isinstance(evidence, list) else [],
        "tags": frontmatter.get("tags", []) if isinstance(frontmatter.get("tags", []), list) else [],
    }


def _parse_simple_frontmatter(frontmatter: str) -> dict[str, Any]:
    result: dict[str, Any] = {}
    for raw_line in frontmatter.splitlines():
        line = raw_line.strip()
        if not line or line.startswith("#") or ":" not in line:
            continue
        key, raw_value = line.split(":", 1)
        value = raw_value.strip()
        if value == "" or value.lower() == "null":
            result[key.strip()] = None
            continue
        if value.startswith(("[", "{", '"')):
            try:
                result[key.strip()] = json.loads(value)
                continue
            except json.JSONDecodeError:
                pass
        result[key.strip()] = value.strip().strip('"').strip("'")
    return result


def _extract_markdown_note_text(body: str) -> str:
    marker = "\n## Evidence"
    index = body.find(marker)
    text = body[:index] if index != -1 else body
    return text.strip()


def _extract_markdown_note_evidence(body: str) -> list[str]:
    marker = "\n## Evidence"
    index = body.find(marker)
    if index == -1:
        return []
    section = body[index + len(marker) :]
    lines: list[str] = []
    for raw_line in section.splitlines():
        line = raw_line.strip()
        if line.startswith("## "):
            break
        if line.startswith("- "):
            lines.append(line[2:].strip())
    return lines


def _hash_embedding(text: str, *, dimensions: int) -> list[float]:
    digest = hashlib.sha256(str(text or "").encode("utf-8")).digest()
    values: list[float] = []
    for index in range(dimensions):
        byte = digest[index % len(digest)]
        values.append((byte / 127.5) - 1.0)
    return values


def _cosine_similarity(left: list[float], right: list[float]) -> float:
    if not left or not right or len(left) != len(right):
        return -1.0
    dot = sum(a * b for a, b in zip(left, right, strict=True))
    left_norm = math.sqrt(sum(a * a for a in left))
    right_norm = math.sqrt(sum(b * b for b in right))
    if left_norm <= 0 or right_norm <= 0:
        return -1.0
    return dot / (left_norm * right_norm)

from __future__ import annotations

import hashlib
from datetime import datetime, timezone
from pathlib import Path

from app.time_utils import utc_now_iso
from typing import Any

from app.obsidian_index.parser import scan_vault, parse_obsidian_file
from app.obsidian_index.chunker import build_obsidian_chunk
from app.vector_memory import VectorMemoryRecord, EmbeddingClient, VectorStore


OBSIDIAN_NAMESPACE = "obsidian_vault"


class ObsidianIndexBuilder:
    def __init__(
        self,
        *,
        embedding_client: EmbeddingClient,
        store: VectorStore,
        chunk_max_chars: int = 3000,
        ignore_dirs: list[str] | None = None,
    ) -> None:
        self.embedding_client = embedding_client
        self.store = store
        self.chunk_max_chars = chunk_max_chars
        self.ignore_dirs = ignore_dirs

    def _unchanged(self, meta: dict[str, Any] | None, item_id: str, text_hash: str) -> bool:
        if not meta:
            return False
        if meta.get("item_id") != item_id:
            return False
        if meta.get("text_hash") != text_hash:
            return False
        if meta.get("embedding_model_id") != self.embedding_client.model_id:
            return False
        if self.embedding_client.dimensions is not None and meta.get("dimensions") != self.embedding_client.dimensions:
            return False
        return True

    def _embed_and_upsert(
        self,
        records_to_embed: list[tuple[str, str, str, str]],
        *,
        namespace: str,
    ) -> int:
        """Embed a batch of (text, source_path, text_hash, item_id) tuples and upsert them."""
        if not records_to_embed:
            return 0
        texts = [t for t, _, _, _ in records_to_embed]
        embeddings = self.embedding_client.embed_texts(texts)
        if len(embeddings) != len(records_to_embed):
            raise RuntimeError("Embedding client returned unexpected vector count.")
        records: list[VectorMemoryRecord] = []
        for (text, source_path, text_hash, item_id), emb in zip(records_to_embed, embeddings, strict=True):
            dim = len(emb)
            records.append(
                VectorMemoryRecord(
                    namespace=namespace,
                    item_id=item_id,
                    source_path=source_path,
                    text=text,
                    text_hash=text_hash,
                    embedding=[float(v) for v in emb],
                    embedding_model_id=self.embedding_client.model_id,
                    dimensions=dim,
                    updated_at=utc_now_iso(),
                )
            )
        if records:
            self.store.ensure_schema(dimensions=records[0].dimensions)
            self.store.upsert(records)
        return len(records)

    def index_file(self, path: Path) -> dict[str, int]:
        """Incrementally index a single Obsidian .md file."""
        if not self.store.available():
            return {"indexed": 0, "skipped": 0, "error": "store not available"}
        if not path.exists() or path.suffix != ".md":
            return {"indexed": 0, "skipped": 0, "error": "not a md file"}
        note = parse_obsidian_file(path)
        if note is None:
            return {"indexed": 0, "skipped": 0}
        source_path = str(note.get("file_path", ""))
        if not source_path:
            return {"indexed": 0, "skipped": 0}
        text = build_obsidian_chunk(note, max_chars=self.chunk_max_chars)
        if not text:
            self.store.delete_by_source_path(namespace=OBSIDIAN_NAMESPACE, source_path=source_path)
            return {"indexed": 0, "skipped": 0, "deleted": 1}
        text_hash = hashlib.sha256(text.encode("utf-8")).hexdigest()
        item_id = _item_id_from_path(path)
        indexed = self.store.indexed_metadata(namespace=OBSIDIAN_NAMESPACE)
        if self._unchanged(indexed.get(source_path), item_id, text_hash):
            return {"indexed": 0, "skipped": 1}
        indexed_count = self._embed_and_upsert(
            [(text, source_path, text_hash, item_id)],
            namespace=OBSIDIAN_NAMESPACE,
        )
        return {"indexed": indexed_count, "skipped": 0}

    def index_paths(self, paths: list[Path]) -> dict[str, int]:
        """Incrementally index a list of .md paths and delete empty/removed ones."""
        total = {"indexed": 0, "skipped": 0, "deleted": 0, "errors": 0}
        if not self.store.available():
            total["error"] = "store not available"
            return total
        for path in paths:
            if not path.suffix == ".md":
                total["errors"] += 1
                continue
            res = self.index_file(path)
            for key in ("indexed", "skipped", "deleted"):
                total[key] += res.get(key, 0)
            if res.get("error"):
                total["errors"] += 1
        return total

    def rebuild(self, vault_path: Path) -> dict[str, int]:
        """Full recursive scan of vault_path — upsert changed, delete missing."""
        if not self.store.available():
            return {"scanned": 0, "indexed": 0, "skipped": 0, "deleted": 0, "error": "store not available"}
        files = scan_vault(vault_path, ignore_dirs=self.ignore_dirs)
        indexed = self.store.indexed_metadata(namespace=OBSIDIAN_NAMESPACE)
        source_paths: set[str] = set()
        records_to_embed: list[tuple[str, str, str, str]] = []
        skipped = 0
        for file_path in files:
            note = parse_obsidian_file(file_path)
            if note is None:
                continue
            source_path = str(note.get("file_path", ""))
            if not source_path:
                continue
            text = build_obsidian_chunk(note, max_chars=self.chunk_max_chars)
            if not text:
                continue
            source_paths.add(source_path)
            text_hash = hashlib.sha256(text.encode("utf-8")).hexdigest()
            item_id = _item_id_from_path(file_path)
            if self._unchanged(indexed.get(source_path), item_id, text_hash):
                skipped += 1
                continue
            records_to_embed.append((text, source_path, text_hash, item_id))
        indexed_count = self._embed_and_upsert(records_to_embed, namespace=OBSIDIAN_NAMESPACE)
        self.store.delete_missing(namespace=OBSIDIAN_NAMESPACE, source_paths=source_paths)
        deleted = max(0, len(indexed) - skipped - indexed_count)
        return {
            "scanned": len(source_paths),
            "indexed": indexed_count,
            "skipped": skipped,
            "deleted": deleted,
        }


def _item_id_from_path(path: Path) -> str:
    return hashlib.sha256(str(path).encode("utf-8")).hexdigest()[:16]
